import { useEffect, useRef, useState } from 'react';
import { motion } from 'framer-motion';
import { Calendar, Eye, TrendingUp, Users } from 'lucide-react';

const MetricCard = ({ Icon, label, targetValue, format = 'int', delay = 0, iconBgColor = '#A78BFA' }) => {
  const [animatedValue, setAnimatedValue] = useState(0);
  const ref = useRef(null);

  useEffect(() => {
    let frameId;
    let timeoutId;

    const durationMs = 2000;
    const easeOutCubic = (time) => 1 - Math.pow(1 - time, 3);

    if (targetValue === 0) {
      setAnimatedValue(0);
      return;
    }

    const startAnimation = () => {
      const startTime = performance.now();

      const animate = (now) => {
        const elapsed = now - startTime;
        const progress = Math.min(elapsed / durationMs, 1);
        const eased = easeOutCubic(progress);

        setAnimatedValue(targetValue * eased);

        if (progress < 1) {
          frameId = requestAnimationFrame(animate);
        }
      };

      frameId = requestAnimationFrame(animate);
    };

    timeoutId = window.setTimeout(startAnimation, delay * 1000);

    return () => {
      if (timeoutId) {
        clearTimeout(timeoutId);
      }
      if (frameId) {
        cancelAnimationFrame(frameId);
      }
    };
  }, [delay, targetValue]);

  const formatValue = (value) => {
    if (format === 'k') {
      return `${Math.round(value / 1000)}K`;
    }

    if (format === 'm') {
      return `${(value / 1000000).toFixed(1)}M`;
    }

    return `${Math.round(value)}`;
  };

  return (
    <motion.div
      ref={ref}
      initial={{ opacity: 0, y: 30 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.6, delay }}
      className="text-center"
    >
      <div
        className="inline-flex items-center justify-center w-12 h-12 rounded-full mb-3"
        style={{ backgroundColor: iconBgColor }}
      >
        <Icon className="w-6 h-6 text-white" />
      </div>
      <div className="font-mono font-bold text-2xl md:text-3xl gradient-text" data-testid={`metric-${label.toLowerCase().replace(/\s/g, '-')}`}>
        {formatValue(animatedValue)}
      </div>
      <p className="text-sm text-muted-foreground mt-1">{label}</p>
    </motion.div>
  );
};

export const CaseStudyMetrics = () => {
  return (
    <section className="py-12 px-4 md:px-0" data-testid="case-study-section">
      <motion.div
        initial={{ opacity: 0, y: 40 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.8 }}
      >
        <div className="relative overflow-hidden rounded-xl border border-border bg-gradient-to-br from-fuchsia-500/10 via-purple-500/5 to-transparent dark:glass-card light:glass-card-light">
          {/* Decorative Elements */}
          <div className="absolute top-0 right-0 w-64 h-64 bg-fuchsia-500/10 rounded-full blur-3xl -translate-y-1/2 translate-x-1/2" />
          <div className="absolute bottom-0 left-0 w-48 h-48 bg-purple-500/10 rounded-full blur-3xl translate-y-1/2 -translate-x-1/2" />
          
          <div className="relative z-10 p-6 md:p-10">
            {/* Header */}
            <div className="text-center mb-10">
              <motion.div
                initial={{ scale: 0 }}
                animate={{ scale: 1 }}
                transition={{ duration: 0.5, type: "spring" }}
                className="inline-flex items-center gap-2 px-4 py-2 rounded-full bg-fuchsia-500/20 text-fuchsia-400 text-sm font-medium mb-4"
              >
                <span className="w-4 h-4 inline-flex items-center justify-center">✨</span>
                Case Study
              </motion.div>
              <h2 className="text-2xl md:text-3xl font-bold mb-2">
                Crecimiento Orgánico en <span className="gradient-text">90 Días</span>
              </h2>
              <p className="text-muted-foreground text-sm md:text-base">
                Estrategia de contenido viral para @sweetdeliriumcookies
              </p>
            </div>

            {/* Metrics Grid */}
            <div className="grid grid-cols-2 md:grid-cols-4 gap-8 md:gap-12">
              <MetricCard 
                Icon={Users}
                label="Seguidores Iniciales" 
                targetValue={0}
                format="int"
                delay={0.1}
                iconBgColor="#6B7FD4"
              />
              <MetricCard 
                Icon={TrendingUp}
                label="Seguidores Actuales" 
                targetValue={128000}
                format="k"
                delay={0.2}
                iconBgColor="#2DD4BF"
              />
              <MetricCard 
                Icon={Eye}
                label="Vistas Totales" 
                targetValue={6400000}
                format="m"
                delay={0.3}
                iconBgColor="#A78BFA"
              />
              <MetricCard 
                Icon={Calendar}
