            {/* BlyxNova Credit */}
            <motion.div 
              className="mt-8 text-center"
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              transition={{ delay: 1 }}
            >
              <p className="text-xs text-muted-foreground">
                Estrategia desarrollada por{' '}
                <span className="blyx-brand font-semibold">BlyxNova Studio</span>
              </p>
